const fs = require('fs');
const path = require('path');

let sharp;
try {
  sharp = require('sharp');
} catch(e) {
  throw new Error('[FOCUST] sharp module not available in n8n: ' + e.message);
}

const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[FOCUST] No Cards found in Deck.json.');
}

const N_STILLS = 6;
const OUT_SIZE = 512;

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error('[FOCUST] No cards matched filter: ' + JSON.stringify(testCardFilter));
}

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  let cardRaw;
  try {
    cardRaw = JSON.parse(fs.readFileSync(cardFilePath, 'utf8').replace(/^﻿/, ''));
  } catch(e) {
    console.warn('[FOCUST] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read card file: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards')).replace(/\//g, path.sep);

  const uprightImageName = card.Assets && card.Assets.UprightImage;
  if (!uprightImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No Assets.UprightImage' });
    continue;
  }

  const uprightRecord = (card.records || []).find(r => r.Orientation === 'upright');
  if (!uprightRecord) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No upright record' });
    continue;
  }

  const cardImageName = uprightRecord.Assets && uprightRecord.Assets.CardImage;
  if (!cardImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No upright record Assets.CardImage' });
    continue;
  }

  const uprightImagePath = path.join(cardDir, uprightImageName);
  const cardImagePath = path.join(cardDir, cardImageName);

  if (!fs.existsSync(uprightImagePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'UprightImage not found: ' + uprightImagePath });
    continue;
  }
  if (!fs.existsSync(cardImagePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'CardImage not found: ' + cardImagePath });
    continue;
  }

  // Get image dimensions
  let uprightMeta, cardMeta;
  try {
    uprightMeta = await sharp(uprightImagePath).metadata();
    cardMeta = await sharp(cardImagePath).metadata();
  } catch(e) {
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read image metadata: ' + e.message });
    continue;
  }

  const uw = uprightMeta.width;   // e.g. 680
  const uh = uprightMeta.height;  // e.g. 1100
  const cw = cardMeta.width;      // e.g. 512
  const ch = cardMeta.height;     // e.g. 512

  // CardImage sits in the top-right of UprightImage with a small border.
  // Derived from template matching: right margin ~6px, top margin ~56px.
  const cx = Math.max(0, uw - cw - 6);
  const cy = 56;

  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const stillNames = Array.from({ length: N_STILLS }, (_, i) =>
    'FOCUST_UPRIGHT_' + slug + '_' + String(i).padStart(2, '0') + '.png');
  const stillPaths = stillNames.map(n => path.join(cardDir, n));

  if (stillPaths.every(p => fs.existsSync(p))) {
    console.warn('[FOCUST] Stills already exist for: ' + cardName + ', skipping.');
    if (!uprightRecord.Assets) uprightRecord.Assets = {};
    uprightRecord.Assets.FocusUprightT = stillNames;
    fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Already generated' });
    continue;
  }

  let generatedAll = true;
  for (let i = 0; i < N_STILLS; i++) {
    const t = i / (N_STILLS - 1);
    const left   = Math.round(cx * t);
    const top    = Math.round(cy * t);
    const right  = Math.round(uw - (uw - (cx + cw)) * t);
    const bottom = Math.round(uh - (uh - (cy + ch)) * t);
    const width  = right - left;
    const height = bottom - top;

    try {
      await sharp(uprightImagePath)
        .extract({ left, top, width, height })
        .resize(OUT_SIZE, OUT_SIZE)
        .png()
        .toFile(stillPaths[i]);
    } catch(e) {
      console.warn('[FOCUST] sharp error frame ' + i + ' of ' + cardName + ': ' + e.message);
      results.failed++;
      results.cards.push({ card: cardName, status: 'failed', reason: 'sharp error frame ' + i + ': ' + e.message });
      generatedAll = false;
      break;
    }
  }

  if (!generatedAll) continue;

  if (!uprightRecord.Assets) uprightRecord.Assets = {};
  uprightRecord.Assets.FocusUprightT = stillNames;
  fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');

  results.processed++;
  results.cards.push({
    card: cardName,
    status: 'generated',
    stills: stillNames,
    cropOrigin: [cx, cy],
    cardImageSize: [cw, ch]
  });
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error('[FOCUST] No cards processed. Check TestCardFilter and Deck.json Cards array.');
}

return [{ json: results }];
